/* --------------------------------- HELPERS --------------------------------- */

function pct(attended, total) { return total === 0 ? 0 : Math.round((attended / total) * 1000) / 10; }

function zoneColor(p) {
  if (p < 50) return "var(--alarm)";
  if (p < REQUIRED) return "var(--warn)";
  return "var(--safe)";
}

function bunkRoom(attended, total, required = REQUIRED) {
  const req = required / 100;
  const maxTotal = Math.floor(attended / req);
  const safe = maxTotal - total;
  if (safe >= 0) return { canBunk: true, count: safe };
  const n = Math.ceil((req * total - attended) / (1 - req));
  return { canBunk: false, count: n };
}

function overallStats(subjects) {
  const attended = subjects.reduce((a, s) => a + s.attended, 0);
  const total = subjects.reduce((a, s) => a + s.total, 0);
  return { attended, total, percent: pct(attended, total) };
}

function polarToCartesian(cx, cy, r, angleDeg) {
  const rad = (angleDeg * Math.PI) / 180;
  return { x: cx + r * Math.cos(rad), y: cy - r * Math.sin(rad) };
}
function describeArc(cx, cy, r, startAngle, endAngle) {
  const start = polarToCartesian(cx, cy, r, startAngle);
  const end = polarToCartesian(cx, cy, r, endAngle);
  const largeArcFlag = Math.abs(startAngle - endAngle) <= 180 ? "0" : "1";
  return `M ${start.x} ${start.y} A ${r} ${r} 0 ${largeArcFlag} 1 ${end.x} ${end.y}`;
}

/* --------------------------------- GAUGE ----------------------------------- */

function BunkGauge({ percent, size = 200 }) {
  const cx = 100, cy = 100, r = 78;
  const angle = 180 - (percent / 100) * 180;
  const needleRot = 90 - angle;
  return (
    <div style={{ width: size, position: "relative" }}>
      <svg viewBox="0 0 200 118" width={size} height={size * 0.59}>
        <path d={describeArc(cx, cy, r, 180, 90)} stroke="var(--alarm)" strokeWidth="18" fill="none" strokeLinecap="butt" />
        <path d={describeArc(cx, cy, r, 90, 45)} stroke="var(--warn)" strokeWidth="18" fill="none" strokeLinecap="butt" />
        <path d={describeArc(cx, cy, r, 45, 0)} stroke="var(--safe)" strokeWidth="18" fill="none" strokeLinecap="butt" />
        <g transform={`rotate(${needleRot} ${cx} ${cy})`}>
          <line x1={cx} y1={cy} x2={cx} y2={cy - 62} stroke="var(--ink)" strokeWidth="4" strokeLinecap="round" />
        </g>
        <circle cx={cx} cy={cy} r="9" fill="var(--ink)" stroke="var(--paper)" strokeWidth="2" />
      </svg>
      <div className="gauge-readout">
        <div className="gauge-num">{percent}%</div>
        <div className="gauge-label mono">ATTENDANCE</div>
      </div>
    </div>
  );
}

function PAChip({ status }) {
  const isPresent = status === "P";
  return (
    <span className={"pa-chip " + (isPresent ? "pa-present" : "pa-absent")}>{status}</span>
  );
}

function SubjectLogRow({ subject }) {
  return (
    <div className="log-row">
      <div className="log-code mono">{subject.code}</div>
      <div className="log-chips">
        {subject.log.map((s, i) => <PAChip key={i} status={s} />)}
      </div>
    </div>
  );
}

function RingGauge({ percent, size = 160 }) {
  const cx = 60, cy = 60, r = 50;
  const c = 2 * Math.PI * r;
  const off = c - (percent / 100) * c;
  const endAngle = 90 - (percent / 100) * 360;
  const tip = polarToCartesian(cx, cy, r, endAngle);
  return (
    <div style={{ width: size, position: "relative" }}>
      <svg viewBox="0 0 120 120" width={size} height={size}>
        <circle cx={cx} cy={cy} r={r} fill="none" stroke="#EFE9D6" strokeWidth="10" />
        <circle
          cx={cx} cy={cy} r={r} fill="none" stroke="var(--accent)" strokeWidth="10"
          strokeDasharray={c} strokeDashoffset={off} strokeLinecap="round"
          transform={`rotate(-90 ${cx} ${cy})`}
        />
        <circle cx={tip.x} cy={tip.y} r="6" fill="var(--ink)" />
      </svg>
      <div className="ring-readout">
        <div className="ring-num">{percent}%</div>
        <div className="ring-label mono">OVERALL %</div>
      </div>
    </div>
  );
}

function SubjectBar({ subject }) {
  const p = pct(subject.attended, subject.total);
  const room = bunkRoom(subject.attended, subject.total);
  return (
    <div className="subject-card">
      <div className="subject-top">
        <div className="subject-name">{subject.name}</div>
        <div className="subject-pct mono" style={{ color: zoneColor(p) }}>{p}%</div>
      </div>
      <div className="bar-track">
        <div className="bar-fill" style={{ width: `${Math.min(p, 100)}%`, background: zoneColor(p) }} />
        <div className="bar-req-line" style={{ left: `${REQUIRED}%` }} />
      </div>
      <div className={"subject-hint mono " + (room.canBunk ? "hint-safe" : "hint-danger")}>
        {room.canBunk
          ? `Safe to bunk ${room.count} more class${room.count === 1 ? "" : "es"}`
          : `Attend next ${room.count} class${room.count === 1 ? "" : "es"} to hit ${REQUIRED}%`}
      </div>
    </div>
  );
}

