function LoginScreen({ onEnter }) {
  const [roll, setRoll] = useState("");
  const [error, setError] = useState("");

  const submit = () => {
    const cleaned = roll.trim();
    const found = STUDENTS.find((s) => s.roll === cleaned);
    if (!found) {
      setError("Roll number not found — try 2408001 to 2408034");
      return;
    }
    setError("");
    onEnter(found);
  };

  return (
    <div className="screen login-screen">
      <div className="login-top">
        <img src={LOGO_URI} alt="BunkBROS" className="brand-mark-img" />
        <div className="brand-tag mono">BUNK SMART. NOT SORRY.</div>
      </div>
      <div className="login-card">
        <div className="input-row">
          <User size={15} color="var(--muted)" />
          <input
            className="input-flat"
            placeholder="Roll no. e.g. 2408001"
            value={roll}
            onChange={(e) => { setRoll(e.target.value); setError(""); }}
            onKeyDown={(e) => e.key === "Enter" && submit()}
          />
        </div>
        <div className="input-row"><Lock size={15} color="var(--muted)" /><input className="input-flat" placeholder="Password" type="password" defaultValue="········" readOnly /></div>
        {error && <div className="login-error mono">{error}</div>}
        <button className="btn-primary btn-block" onClick={submit}>Clock in</button>
        <div className="login-hint mono">FYBCA · Room 412 · roll 2408001–2408034 · try 2408001 for full access</div>
      </div>
    </div>
  );
}

